            </div>
        </div>

        {/* Task Grid Header */}
        <div className="hidden md:grid grid-cols-12 gap-4 px-6 py-3 bg-stone-50 border-b border-stone-200 text-xs font-bold text-stone-500 uppercase tracking-wider shrink-0">
