            >
              <div className="flex justify-between items-start md:contents">
                  <div className="md:col-span-2 order-2 md:order-1 flex gap-2 items-center">
                    <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-bold bg-stone-200 text-stone-600 truncate max-w-[100px]">
                      {task.category}
