                {/* Standard Filters */}
                <div className="relative shrink-0">
                  <select value={filterCategory} onChange={e => setFilterCategory(e.target.value)} className="appearance-none bg-white border border-stone-200 text-xs font-medium text-stone-600 rounded-full px-3 py-1.5 pr-7 focus:outline-none focus:border-primary cursor-pointer">
                    <option value="ALL">All Categories</option>
                    {allCategories.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                  <ChevronDown size={12} className="absolute right-2 top-1/2 -translate-y-1/2 text-stone-400 pointer-events-none" />
                </div>

                <div className="relative shrink-0">
                  <select value={filterStatus} onChange={e => setFilterStatus(e.target.value as any)} className="appearance-none bg-white border border-stone-200 text-xs font-medium text-stone-600 rounded-full px-3 py-1.5 pr-7 focus:outline-none focus:border-primary cursor-pointer">
