                  <ChevronDown size={12} className="absolute right-2 top-1/2 -translate-y-1/2 text-stone-400 pointer-events-none" />
                </div>

                {/* Desktop Search */}
                <div className="relative hidden md:block ml-auto">
                   <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-400" size={14} />
                   <input 
                     type="text" 
                     placeholder="Search..." 
                     value={searchQuery}
                     onChange={e => setSearchQuery(e.target.value)}
                     className="pl-8 pr-3 py-1.5 bg-white border border-stone-200 rounded-full text-xs focus:outline-none focus:ring-1 focus:ring-primary w-40 transition-all focus:w-60"
