export const updateUser = async (updatedUser: User): Promise<boolean> => {
  const { error } = await supabase
    .from('users')
    .update({ pin: updatedUser.pin }) // Only pin update supported via UI currently
    .eq('id', updatedUser.id);

  return !error;
};

export const logoutUser = () => {
  localStorage.removeItem(CURRENT_USER_KEY);
};

export const addTeamMembers = async (adminId: string, memberIds: string[]): Promise<boolean> => {
  const inserts = memberIds.map(mid => ({
    admin_id: adminId,
    member_id: mid
  }));

  const { error } = await supabase.from('team_memberships').upsert(inserts, { onConflict: 'admin_id,member_id' });
  return !error;
};

