// Sub-component for adding updates
const AddUpdateBar: React.FC<{task: Task, currentUser: User | null, onUpdateAdded: (u: TaskUpdate) => void}> = ({ task, currentUser, onUpdateAdded }) => {
    const [text, setText] = useState('');
    const [isPolishing, setIsPolishing] = useState(false);

    const handleSend = async () => {
        if (!text.trim() || !currentUser) return;

        setIsPolishing(true);
        // Polish text with Gemini
        const polished = await polishUpdateText(text, task.title, task.status);

        const newUpdate: TaskUpdate = {
            id: Date.now().toString(),
            taskId: task.id,
            date: new Date().toISOString().split('T')[0],
            content: polished,
            timestamp: Date.now(),
            isArchived: false,
        };

        await saveSingleUpdate(newUpdate);
        onUpdateAdded(newUpdate);
        setText('');
        setIsPolishing(false);
    };

    return (
        <div className="bg-white border-t p-3 sticky bottom-0 flex gap-2 items-end">
            <textarea 
                className="flex-1 bg-slate-100 rounded-xl px-4 py-2.5 text-sm outline-none focus:ring-2 focus:ring-blue-500 resize-none"
                rows={1}
                placeholder="Add an update..."
                value={text}
                onChange={e => setText(e.target.value)}
                onKeyDown={e => {
                    if(e.key === 'Enter' && !e.shiftKey) {
                        e.preventDefault();
                        handleSend();
                    }
                }}
            />
            <button 
                disabled={!text.trim() || isPolishing}
                onClick={handleSend}
                className="p-2.5 bg-blue-600 text-white rounded-full disabled:opacity-50 hover:bg-blue-700"
            >
                {isPolishing ? <Loader2 className="animate-spin" size={18} /> : <Send size={18} />}
            </button>
        </div>
    );
}

