            {/* Mobile Sort Bar */}
             <div className="md:hidden px-4 py-2 border-t border-stone-100 flex items-center justify-end gap-2 bg-stone-50/30">
                <span className="text-[10px] font-bold text-stone-400 uppercase">Sort By:</span>
                <div className="relative shrink-0">
                  <select 
