```tsx
// MultiSelectDropdown.tsx
import React, { useState } from 'react';
import { Check, ChevronDown, CheckCircle } from 'lucide-react';

interface Option {
  value: string;
  label: string;
}

interface MultiSelectDropdownProps {
  options: Option[];
  selected: string[];
  onChange: (values: string[]) => void;
  placeholder?: string;
  multiple?: boolean;
}

const MultiSelectDropdown: React.FC<MultiSelectDropdownProps> = ({
  options,
  selected,
  onChange,
  placeholder = 'Select an option',
  multiple = true,
}) => {
  const [isOpen, setIsOpen] = useState(false);

  const toggleDropdown = () => setIsOpen(!isOpen);

  const handleSelect = (value: string) => {
    if (multiple) {
      if (selected.includes(value)) {
        onChange(selected.filter((item) => item !== value));
      } else {
        onChange([...selected, value]);
      }
    } else {
      onChange([value]);
      setIsOpen(false);
    }
  };

  return (
    <div className="relative inline-block text-left">
      <button
        type="button"
        className="inline-flex justify-between w-full rounded-md border border-gray-300 shadow-sm px-4 py-2 bg-white text-sm font-medium text-gray-700 hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500"
        onClick={toggleDropdown}
      >
        {selected.length > 0 ? selected.map((s, i) => <span key={i}>{options.find(o => o.value === s)?.label}{i < selected.length -1 ? ', ' : ''}</span>) : placeholder}
        <ChevronDown className="ml-2 -mr-1 h-5 w-5 text-gray-400" aria-hidden="true" />
      </button>

      {isOpen && (
        <div className="origin-top-right absolute right-0 mt-2 w-56 rounded-md shadow-lg bg-white ring-1 ring-black ring-opacity-5 focus:outline-none z-10">
          <div className="py-1" role="menu" aria-orientation="vertical" aria-labelledby="options-menu">
            {options.map((option) => (
              <button
                key={option.value}
                onClick={() => handleSelect(option.value)}
                className="block px-4 py-2 text-sm text-gray-700 hover:bg-gray-100 hover:text-gray-900 w-full text-left"
                role="menuitem"
              >
                {multiple ? (
                  <>
                    {selected.includes(option.value) ? (
                      <CheckCircle className="inline-block mr-2" size={16} />
                    ) : (
                      <Check className="inline-block mr-2 text-gray-400" size={16} />
                    )}
                  </>
                ) : (
                  <>
                    {selected[0] === option.value ? (
                      <CheckCircle className="inline-block mr-2" size={16} />
                    ) : (
                      <span className="opacity-0"> &nbsp; </span>
                    )}
                  </>
                )}
                {option.label}
              </button>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default MultiSelectDropdown;
```

**Building Multi-Select Component**

I've successfully created the `MultiSelectDropdown` component, which manages state using `useState`, supporting multiple selections. I've integrated it into the app, replacing the standard dropdown. I'm focusing on seamless integration, ensuring the `onChange` event properly updates the parent's state. I've also updated the time filter options to improve clarity. Now, I need to test that this is working as I intend.

