import React, { useState, useRef, useEffect } from 'react';
import { ChevronDown, Check, X } from 'lucide-react';

interface Option {
  value: string;
  label: string;
}

interface MultiSelectProps {
  label: string;
  options: Option[];
  selected: string[];
  onChange: (selected: string[]) => void;
  colorClass?: string;
  align?: 'left' | 'right';
}

const MultiSelectDropdown: React.FC<MultiSelectProps> = ({ 
  label, 
  options, 
  selected, 
  onChange, 
  colorClass = "bg-white border-stone-200",
  align = 'left'
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const toggleOption = (value: string) => {
    if (selected.includes(value)) {
      onChange(selected.filter(v => v !== value));
    } else {
      onChange([...selected, value]);
    }
  };

  const clearAll = (e: React.MouseEvent) => {
     e.stopPropagation();
     onChange([]);
  };

  return (
    <div className="relative shrink-0" ref={containerRef}>
      <button
        onClick={() => setIsOpen(!isOpen)}
        className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-bold border shadow-sm transition-all select-none ${colorClass} ${selected.length > 0 ? 'ring-2 ring-primary/20 border-primary text-secondary' : 'text-stone-600'}`}
      >
        <span>{label}</span>
        {selected.length > 0 && (
            <span className="flex items-center justify-center bg-secondary text-primary w-4 h-4 rounded-full text-[9px] pointer-events-none">
                {selected.length}
            </span>
        )}
        <ChevronDown size={12} className={`transition-transform duration-200 ${isOpen ? 'rotate-180' : ''}`} />
      </button>

      {isOpen && (
        <div className={`absolute top-full mt-2 ${align === 'right' ? 'right-0' : 'left-0'} w-56 bg-white rounded-xl shadow-xl border border-stone-100 z-50 animate-in fade-in zoom-in-95 duration-100 overflow-hidden`}>
            <div className="p-2 border-b border-stone-100 flex justify-between items-center bg-stone-50/50">
                <span className="text-[10px] font-bold text-stone-400 uppercase tracking-wider">Select {label}</span>
                {selected.length > 0 && (
                    <button onClick={clearAll} className="text-[10px] text-red-500 font-bold hover:underline flex items-center gap-1">
                        <X size={10} /> Clear
                    </button>
                )}
            </div>
            <div className="max-h-60 overflow-y-auto p-1 scrollbar-thin scrollbar-thumb-stone-200">
                {options.map(opt => {
                    const isSelected = selected.includes(opt.value);
                    return (
                         <div 
                            key={opt.value} 
                            onClick={() => toggleOption(opt.value)}
                            className={`flex items-center gap-3 px-3 py-2 rounded-lg cursor-pointer transition-colors ${isSelected ? 'bg-amber-50' : 'hover:bg-stone-50'}`}
                         >
                            <div className={`w-4 h-4 rounded border flex items-center justify-center transition-colors shrink-0 ${isSelected ? 'bg-primary border-primary' : 'border-stone-300 bg-white'}`}>
                                {isSelected && <Check size={10} className="text-secondary" />}
                            </div>
                            <span className={`text-xs font-medium truncate ${isSelected ? 'text-secondary' : 'text-stone-600'}`}>{opt.label}</span>
                         </div>
                    )
                })}
                {options.length === 0 && (
                    <div className="p-3 text-center text-xs text-stone-400">No options available</div>
                )}
            </div>
        </div>
      )}
    </div>
  );
};

export default MultiSelectDropdown;

