import React, { useState, useEffect } from 'react';
import { generateTasks, Task, SortOrder, FilterValues } from './data';
import { MdDateRange, MdSearch } from 'react-icons/md';
import { FaFilter } from 'react-icons/fa';
import { ChevronDownIcon } from '@heroicons/react/20/solid';

function App() {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [history, setHistory] = useState<Task[]>([]);
  const [filter, setFilter] = useState<FilterValues>({
    time: 'ALL',
    search: '',
    sort: 'FAR_TO_NEAR', // Default sort
  });
  const [historySort, setHistorySort] = useState<SortOrder>('NEWEST');

  useEffect(() => {
    // Generate some tasks, replace with your data fetching logic
    const generatedTasks = generateTasks(50);
    setTasks(generatedTasks);
