                    Add Selected ({selectedTeamMemberIds.length})
                 </button>
              </div>
           </div>
        </div>
      )}

      {/* VOICE OVERLAY */}
      {(isRecording || isProcessingVoice) && (
        <div className="absolute inset-0 z-50 bg-secondary/90 flex flex-col items-center justify-center backdrop-blur-sm">
          {isRecording ? (
             <>
              <div className="w-24 h-24 bg-red-500 rounded-full flex items-center justify-center mb-8 animate-pulse shadow-[0_0_30px_rgba(239,68,68,0.6)]">
