                        <ChevronDown size={12} className="text-stone-400" />
                    </button>

                    {activeFilterDropdown === 'STATUS' && (
                        <>
                            <div className="fixed inset-0 z-30" onClick={() => setActiveFilterDropdown(null)}></div>
                            <div className="absolute top-full mt-2 left-0 z-40 bg-white border border-stone-200 rounded-xl shadow-xl p-2 min-w-[200px] flex flex-col gap-1 max-h-[300px] overflow-y-auto">
                                <div 
                                    onClick={() => setFilterStatuses([])}
                                    className="flex items-center gap-2 px-3 py-2 hover:bg-stone-50 rounded-lg cursor-pointer text-xs font-bold text-stone-600"
                                >
                                   {filterStatuses.length === 0 ? <CheckSquare size={14} className="text-primary"/> : <Square size={14} className="text-stone-300"/>}
                                   All Statuses
                                </div>
