                    Cancel
                 </button>
                 <button 
                    onClick={handleConfirmAdminUpdate}
                    className="flex-1 py-3 text-sm font-bold text-white bg-secondary hover:bg-black rounded-xl transition-colors shadow-lg"
                 >
                    Confirm Update
                 </button>
              </div>
           </div>
        </div>
      )}

      {/* TEAM MODAL */}
      {showTeamModal && (
        <div className="absolute inset-0 z-50 bg-secondary/50 backdrop-blur-sm flex items-center justify-center p-4">
           <div className="bg-white rounded-2xl w-full max-w-sm p-6 shadow-2xl animate-in zoom-in-95 duration-200 flex flex-col max-h-[80vh]">
              <div className="flex justify-between items-center mb-4 shrink-0">
                 <h3 className="text-lg font-bold text-secondary">Add Line Members</h3>
                 <button onClick={() => { setShowTeamModal(false); setSelectedTeamMemberIds([]); }} className="p-1 hover:bg-stone-100 rounded-full"><X size={20}/></button>
              </div>
              <p className="text-stone-500 text-sm mb-4 shrink-0">Select users to add to your reporting line.</p>

              <div className="flex-1 overflow-y-auto mb-4 border border-stone-200 rounded-xl min-h-[150px]">
                {availableUsersToAdd.length === 0 ? (
                  <div className="h-full flex flex-col items-center justify-center text-stone-400 p-4">
                    <Users size={32} className="mb-2 opacity-30" />
                    <p className="text-sm text-center">No other members available to add.</p>
                  </div>
                ) : (
                  <div className="divide-y divide-stone-100">
                    {availableUsersToAdd.map(user => (
                      <label key={user.id} className="flex items-center p-3 hover:bg-stone-50 cursor-pointer group transition-colors">
                        <div className="relative flex items-center justify-center mr-3">
                           <input 
                             type="checkbox" 
                             checked={selectedTeamMemberIds.includes(user.id)}
                             onChange={() => handleToggleTeamMember(user.id)}
                             className="peer appearance-none w-5 h-5 border-2 border-stone-300 rounded checked:bg-primary checked:border-primary transition-all"
                           />
                           <CheckSquare size={14} className="absolute text-secondary opacity-0 peer-checked:opacity-100 pointer-events-none transform scale-0 peer-checked:scale-100 transition-transform" />
                        </div>
                        <div className="flex-1">
                           <div className="font-bold text-stone-700">{user.username}</div>
                           <div className="text-[10px] font-bold text-stone-400 uppercase">{user.role}</div>
                        </div>
                      </label>
                    ))}
                  </div>
                )}
              </div>

              <div className="flex gap-2 shrink-0">
                 <button onClick={() => { setShowTeamModal(false); setSelectedTeamMemberIds([]); }} className="flex-1 py-3 font-bold text-stone-500 hover:bg-stone-50 rounded-xl">Cancel</button>
                 <button 
                    onClick={handleAddSelectedMembers} 
                    disabled={selectedTeamMemberIds.length === 0}
                    className="flex-1 py-3 bg-secondary text-primary font-bold rounded-xl hover:bg-stone-800 disabled:opacity-50 disabled:cursor-not-allowed transition-all active:scale-95"
                 >
                    Add Selected ({selectedTeamMemberIds.length})
                 </button>
              </div>
           </div>
        </div>
      )}

      {/* VOICE OVERLAY */}
      {(isRecording || isProcessingVoice) && (
        <div className="absolute inset-0 z-50 bg-secondary/90 flex flex-col items-center justify-center backdrop-blur-sm">
          {isRecording ? (
             <>
              <div className="w-24 h-24 bg-red-500 rounded-full flex items-center justify-center mb-8 animate-pulse shadow-[0_0_30px_rgba(239,68,68,0.6)]">
                <Mic size={48} className="text-white" />
              </div>
              <p className="text-white text-lg font-medium mb-2">Listening...</p>
              <button onClick={stopRecording} className="bg-white text-secondary px-8 py-3 rounded-full font-bold flex items-center gap-2 mt-4 hover:bg-stone-100 transition-colors">
                <MicOff size={20} /> Stop & Create
              </button>
             </>
          ) : (
             <>
              <Loader2 size={48} className="text-primary animate-spin mb-6" />
              <p className="text-white text-lg font-medium">Creating Task...</p>
             </>
          )}
        </div>
      )}

      {/* HEADER SECTION */}
      <div className={`flex-col bg-beige border-b border-stone-200 transition-all duration-300 absolute inset-0 bottom-16 md:bottom-auto md:relative md:h-1/2 md:flex ${activeTab === 'overview' ? 'flex z-20' : 'hidden md:flex'}`}>
        {/* Top Bar */}
        <div className="h-16 flex items-center justify-between px-4 md:px-6 border-b border-stone-200 shrink-0 bg-beige">
          <div className="flex items-center gap-3">
            <div className="w-8 h-8 bg-primary rounded-lg flex items-center justify-center text-secondary font-bold shadow-sm">DP</div>
            <div>
              <h1 className="text-base md:text-xl font-bold text-secondary leading-tight">DailyPulse</h1>
              <p className="text-[10px] md:text-xs text-stone-500 font-bold uppercase tracking-wider">{currentUser.role === 'ADMIN' ? 'Admin Dashboard' : 'Member Workspace'}</p>
            </div>
          </div>

          <div className="flex items-center gap-2 md:gap-3">
             {currentUser.role === 'ADMIN' && (
               <button 
                  onClick={() => setShowTeamModal(true)}
                  className="p-2 md:px-3 md:py-2 bg-white border border-stone-200 rounded-full text-secondary hover:bg-stone-50 transition-colors flex items-center gap-2"
                  title="Add Member"
               >
                 <UserPlus size={18} /> <span className="hidden md:inline text-xs font-bold">Add Member</span>
               </button>
             )}

             <button 
                onClick={startRecording}
                className="p-2 md:px-3 md:py-2 bg-white hover:bg-stone-50 text-secondary rounded-full transition-colors border border-stone-200 shadow-sm flex items-center gap-2"
             >
                <Mic size={18} /> <span className="hidden md:inline text-xs font-bold">Voice</span>
             </button>

             <button onClick={createNewTask} className="p-2 md:px-4 md:py-2 bg-secondary hover:bg-stone-800 text-primary rounded-full text-xs md:text-sm font-bold transition-colors shadow-md flex items-center gap-2">
               <Plus size={16} /> <span className="hidden md:inline">New Task</span>
             </button>

             {/* Desktop Profile Button */}
             <button onClick={() => setActiveTab('profile')} className="p-2 text-stone-500 hover:text-secondary transition-colors" title="My Profile">
               <UserIcon size={18} />
             </button>

             <button onClick={handleLogout} className="p-2 text-stone-400 hover:text-red-500 transition-colors" title="Logout">
               <LogOut size={18} />
             </button>
          </div>
        </div>

        {/* Filters Bar */}
        <div className="flex flex-col border-b border-stone-200 bg-stone-50/50 shrink-0">
            {/* Mobile Search */}
            <div className="md:hidden px-4 py-3 border-b border-stone-100">
               <div className="relative">
                 <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-400" size={16} />
                 <input type="text" placeholder="Search..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} className="w-full pl-9 pr-4 py-2 bg-white border border-stone-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-primary/50" />
               </div>
            </div>

            {/* Filter Controls */}
            <div className="flex items-center px-4 md:px-6 py-3 gap-2 overflow-x-auto scrollbar-hide">
                <Filter size={14} className="text-stone-400 shrink-0" />

                {/* Admin User Filter */}
                {currentUser.role === 'ADMIN' && (
                  <div className="relative shrink-0">
                    <select value={filterUser} onChange={e => setFilterUser(e.target.value)} className="appearance-none bg-stone-800 text-white border border-stone-800 text-xs font-bold rounded-full px-3 py-1.5 pr-7 focus:outline-none cursor-pointer">
                      <option value="ALL_TEAM">All Team</option>
                      <option value="ME">My Tasks</option>
                      {teamMembers.map(m => (
                        <option key={m.id} value={m.id}>{m.username}</option>
                      ))}
                    </select>
                    <ChevronDown size={12} className="absolute right-2 top-1/2 -translate-y-1/2 text-stone-400 pointer-events-none" />
                  </div>
                )}

                {/* Multi-Select Category Filter */}
                <div className="relative shrink-0">
                    <button 
                        onClick={() => setActiveFilterDropdown(activeFilterDropdown === 'CATEGORY' ? null : 'CATEGORY')}
                        className={`appearance-none flex items-center gap-2 border text-xs font-medium rounded-full px-3 py-1.5 focus:outline-none transition-colors ${filterCategories.length > 0 ? 'bg-primary/10 border-primary text-secondary' : 'bg-white border-stone-200 text-stone-600'}`}
                    >
                        <span>
                            {filterCategories.length === 0 
                                ? 'All Categories' 
                                : filterCategories.length === 1 
                                    ? filterCategories[0] 
                                    : `${filterCategories.length} Categories`}
                        </span>
                        <ChevronDown size={12} className="text-stone-400" />
                    </button>

                    {activeFilterDropdown === 'CATEGORY' && (
                        <>
                            <div className="fixed inset-0 z-30" onClick={() => setActiveFilterDropdown(null)}></div>
                            <div className="absolute top-full mt-2 left-0 z-40 bg-white border border-stone-200 rounded-xl shadow-xl p-2 min-w-[200px] flex flex-col gap-1 max-h-[300px] overflow-y-auto">
                                <div 
                                    onClick={() => setFilterCategories([])}
                                    className="flex items-center gap-2 px-3 py-2 hover:bg-stone-50 rounded-lg cursor-pointer text-xs font-bold text-stone-600"
                                >
                                   {filterCategories.length === 0 ? <CheckSquare size={14} className="text-primary"/> : <Square size={14} className="text-stone-300"/>}
                                   All Categories
                                </div>
                                <div className="h-px bg-stone-100 my-1"></div>
                                {allCategories.map(cat => {
                                    const isSelected = filterCategories.includes(cat);
                                    return (
                                        <div 
                                            key={cat}
                                            onClick={() => {
                                                setFilterCategories(prev => 
                                                    prev.includes(cat) 
                                                        ? prev.filter(c => c !== cat) 
                                                        : [...prev, cat]
