      {/* Mobile Nav */}
      <div className="fixed bottom-0 left-0 right-0 h-16 bg-white border-t border-stone-200 flex md:hidden z-50 pb-safe">
         <button onClick={() => setActiveTab('overview')} className={`flex-1 flex flex-col items-center justify-center gap-1 ${activeTab === 'overview' ? 'text-primary' : 'text-stone-300'}`}>
