                   <div className="flex items-center gap-2 bg-white border border-stone-200 rounded-full px-4 py-1.5 shadow-sm hover:border-primary transition-all group">
                      <span className="text-xs font-bold text-stone-400 uppercase tracking-wider mr-2">Update Date:</span>
                      <Calendar size={14} className="text-stone-400 group-hover:text-primary" />
                      <input 
                          type="date" 
                          value={updateDate}
                          onChange={(e) => setUpdateDate(e.target.value)}
                          className="text-xs font-mono text-stone-600 bg-transparent outline-none cursor-pointer w-24"
                      />
                   </div>
                 </div>

                 <div className="relative md:flex-1">
                    <textarea 
                      className="w-full h-20 md:h-full p-3 bg-stone-50 border border-stone-200 rounded-xl resize-none focus:outline-none focus:ring-2 focus:ring-primary/30 focus:bg-white transition-all text-sm leading-relaxed text-secondary placeholder:text-stone-400"
                      placeholder="Type your update here..."
                      value={updateContent}
                      onChange={e => setUpdateContent(e.target.value)}
                    />
                    {updateContent.length > 10 && (
                      <button 
                        onClick={handlePolish}
                        disabled={isPolishing}
                        className="absolute bottom-2 right-2 p-1.5 bg-white shadow-sm border border-stone-200 rounded-lg hover:bg-primary hover:text-secondary text-stone-500 transition-all hover:scale-105 disabled:opacity-50"
                      >
                        {isPolishing ? <div className="w-3 h-3 border-2 border-stone-600 border-t-transparent rounded-full animate-spin" /> : <Wand2 size={14} />}
                      </button>
                    )}
                 </div>
               </div>

               <div className="mt-4 flex justify-between items-center shrink-0">
                  {editUpdateId ? (
                    <div className="flex items-center gap-2">
                         <span className="text-xs text-amber-600 font-bold bg-amber-100 px-2 py-1 rounded hidden sm:inline">Editing</span>
                         <button onClick={handleCancelEdit} className="p-1 hover:bg-stone-100 rounded-full text-stone-400 hover:text-stone-600"><X size={14}/></button>
                    </div>
                  ) : <span />}
                  <button onClick={handleSaveUpdate} className="bg-secondary hover:bg-stone-800 text-primary px-6 py-2.5 rounded-xl text-sm font-bold flex items-center gap-2 transition-transform active:scale-95 shadow-lg shadow-stone-200 w-full sm:w-auto justify-center" disabled={isSaving}>
                    {isSaving ? <Loader2 size={16} className="animate-spin" /> : <Save size={16} />} 
                    {editUpdateId ? 'Update' : 'Save'}
                  </button>
               </div>
            </div>

            {/* History Side */}
            <div className="flex-1 md:w-1/2 p-4 md:p-8 bg-stone-50 flex flex-col overflow-hidden min-h-[300px] md:min-h-0 animate-fade-in">
              <div className="flex justify-between items-center mb-4 md:mb-6 shrink-0">
                <h2 className="text-lg font-bold text-secondary">History</h2>
                <div className="flex bg-white p-1 rounded-lg border border-stone-200">
                   <button 
                      onClick={() => setHistorySort(prev => prev === 'NEWEST' ? 'OLDEST' : 'NEWEST')}
                      className="px-3 py-1.5 text-xs font-bold rounded-lg bg-white border border-stone-100 hover:bg-stone-50 text-stone-600 flex items-center gap-1 transition-colors"
                   >
                       {historySort === 'OLDEST' ? <ArrowUp size={12}/> : <ArrowDown size={12}/>}
                       {historySort === 'OLDEST' ? 'Date Asc' : 'Date Desc'}
                   </button>
                </div>
              </div>

              <div className="flex-1 overflow-y-auto pr-2 -mr-2 pb-20 md:pb-0">
                 {taskHistory.length === 0 ? (
                   <div className="flex flex-col items-center justify-center h-32 text-stone-400 mt-4">
                      <AlertCircle size={24} className="mb-2 opacity-30" />
                      <p className="text-sm">No updates yet.</p>
                   </div>
                 ) : (
                   taskHistory.map(update => (
                     <SwipeableCard 
                        key={update.id} 
                        update={update} 
                        onEdit={handleEditUpdateStart}
                        onCalendar={handleAddToCalendar}
                        onDelete={handleDeleteUpdate}
                     />
                   ))
                 )}
              </div>
            </div>
          </>
        ) : (
          <div className="w-full h-full flex flex-col items-center justify-center text-stone-400 bg-stone-50/50 p-6 text-center animate-fade-in">
            <CheckCircle2 size={48} className="mb-4 opacity-20 text-primary" />
            <p className="text-lg font-bold text-stone-500">No Task Selected</p>
            <p className="text-sm opacity-60 mt-2">Select a task from the list to view details.</p>
            <button onClick={() => setActiveTab('overview')} className="mt-4 px-6 py-2 bg-white border border-stone-200 rounded-full text-sm font-bold text-primary shadow-sm md:hidden">Go to Overview</button>
          </div>
        )}
      </div>

      {/* Mobile Nav */}
      <div className="fixed bottom-0 left-0 right-0 h-16 bg-white border-t border-stone-200 flex md:hidden z-50 pb-safe">
         <button onClick={() => setActiveTab('overview')} className={`flex-1 flex flex-col items-center justify-center gap-1 ${activeTab === 'overview' ? 'text-primary' : 'text-stone-300'}`}>
            <LayoutList size={20} /> <span className="text-[10px] font-bold">Overview</span>
         </button>
         <button onClick={() => setActiveTab('detail')} className={`flex-1 flex flex-col items-center justify-center gap-1 ${activeTab === 'detail' ? 'text-primary' : 'text-stone-300'}`}>
            <FileText size={20} /> <span className="text-[10px] font-bold">Detail</span>
         </button>
         <button onClick={() => setActiveTab('chat')} className={`flex-1 flex flex-col items-center justify-center gap-1 ${activeTab === 'chat' ? 'text-primary' : 'text-stone-300'}`}>
            <MessageSquare size={20} /> <span className="text-[10px] font-bold">Chat</span>
         </button>
         <button onClick={() => setActiveTab('profile')} className={`flex-1 flex flex-col items-center justify-center gap-1 ${activeTab === 'profile' ? 'text-primary' : 'text-stone-300'}`}>
            <UserIcon size={20} /> <span className="text-[10px] font-bold">Profile</span>
         </button>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Plus, Search, Filter, Calendar, ChevronDown, Save, Wand2, AlertCircle, AlertTriangle, CheckCircle2, X, LayoutList, FileText, Mic, Loader2, MicOff, LogOut, Users, UserPlus, Shield, User as UserIcon, CheckSquare, Square, Settings, Lock, ArrowUpDown, ArrowUp, ArrowDown, MessageSquare, Send, Bot } from 'lucide-react';
import { Task, TaskUpdate, TaskStatus, FilterTime, SortOrder, User, UserRole } from './types';
import { STATUS_COLORS, CATEGORIES, STATUSES } from './constants';
import { getTasks, saveSingleTask, getUpdates, saveSingleUpdate, deleteUpdate, loginUser, registerUser, logoutUser, getCurrentUser, getUsers, addTeamMembers, updateUser } from './services/storageService';
import { polishUpdateText, createTaskFromVoice, chatWithAI } from './services/geminiService';
import SwipeableCard from './components/SwipeableCard';

type TaskSortOption = 'DATE_ASC' | 'DATE_DESC' | 'STATUS_ASC' | 'STATUS_DESC' | 'CATEGORY_ASC' | 'CATEGORY_DESC';

const App: React.FC = () => {
  // --- Auth State ---
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [authMode, setAuthMode] = useState<'LOGIN' | 'REGISTER'>('LOGIN');
  const [authUsername, setAuthUsername] = useState('');
  const [authPin, setAuthPin] = useState('');
  const [authRole, setAuthRole] = useState<UserRole>('MEMBER');
  const [authError, setAuthError] = useState('');
  const [authLoading, setAuthLoading] = useState(false);

  // --- App State ---
  const [tasks, setTasks] = useState<Task[]>([]);
  const [updates, setUpdates] = useState<TaskUpdate[]>([]);
  const [isLoadingData, setIsLoadingData] = useState(false);

  const [selectedTaskId, setSelectedTaskId] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'overview' | 'detail' | 'profile' | 'chat'>('overview');

  // Filters & Sorting
  const [filterCategory, setFilterCategory] = useState<string>('ALL');
  const [filterStatus, setFilterStatus] = useState<string>('ALL');

  const [activeFilterDropdown, setActiveFilterDropdown] = useState<'SORT' | null>(null);

  const [filterTime, setFilterTime] = useState<FilterTime>('ALL');
  const [filterUser, setFilterUser] = useState<string>('ALL_TEAM'); 
  const [taskSort, setTaskSort] = useState<TaskSortOption>('DATE_ASC');
  const [searchQuery, setSearchQuery] = useState('');

  // Team Management State
  const [showTeamModal, setShowTeamModal] = useState(false);
  const [selectedTeamMemberIds, setSelectedTeamMemberIds] = useState<string[]>([]);
  const [allUsers, setAllUsers] = useState<User[]>([]); // Cache for users

  // Admin Confirmation State
  const [showAdminConfirmModal, setShowAdminConfirmModal] = useState(false);

  // Detail View State
  const [updateDate, setUpdateDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [updateContent, setUpdateContent] = useState('');
  const [isPolishing, setIsPolishing] = useState(false);
  const [historySort, setHistorySort] = useState<SortOrder>('NEWEST');
  const [editUpdateId, setEditUpdateId] = useState<string | null>(null);
  const [isSaving, setIsSaving] = useState(false);

  // Profile View State
  const [newPin, setNewPin] = useState('');
  const [confirmPin, setConfirmPin] = useState('');
  const [profileMessage, setProfileMessage] = useState<{type: 'success'|'error', text: string} | null>(null);

  // Chat State
  const [chatMessages, setChatMessages] = useState<{role: 'user' | 'model', text: string}[]>([
     { role: 'model', text: "Hi! I'm your AI assistant. I can answer questions about your tasks and team updates." }
  ]);
  const [chatInput, setChatInput] = useState('');
  const [isChatLoading, setIsChatLoading] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  const [lastStatus, setLastStatus] = useState<TaskStatus>(TaskStatus.NOT_YET);

  // Voice Recorder State
  const [isRecording, setIsRecording] = useState(false);
  const [isProcessingVoice, setIsProcessingVoice] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);

  // --- Initialization ---

  useEffect(() => {
    // Check for logged in user
    const checkUser = async () => {
        const user = await getCurrentUser();
        if (user) {
          setCurrentUser(user);
          loadData();
        }
    };
    checkUser();
  }, []);

  useEffect(() => {
    if (activeTab === 'chat') {
      chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [chatMessages, activeTab]);

  const loadData = async () => {
    setIsLoadingData(true);
    const [fetchedTasks, fetchedUpdates, fetchedUsers] = await Promise.all([
        getTasks(),
        getUpdates(),
        getUsers()
    ]);
    setTasks(fetchedTasks);
    setUpdates(fetchedUpdates);
    setAllUsers(fetchedUsers);
    setIsLoadingData(false);
  };

  // Reset form when switching tasks
  useEffect(() => {
    if (selectedTaskId) {
      setUpdateContent('');
      setUpdateDate(new Date().toISOString().split('T')[0]);
      setEditUpdateId(null);
      setIsPolishing(false);

      const t = tasks.find(x => x.id === selectedTaskId);
      if (t) {
        setLastStatus(t.status);
      }
    }
  }, [selectedTaskId]);

  // --- Auth Actions ---

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setAuthLoading(true);
    const user = await loginUser(authUsername, authPin);
    if (user) {
      setCurrentUser(user);
      await loadData();
      setAuthError('');
      setAuthUsername('');
      setAuthPin('');
    } else {
      setAuthError('Invalid username or PIN');
    }
    setAuthLoading(false);
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    if (authPin.length < 4) {
      setAuthError('PIN must be at least 4 digits');
      return;
    }
    setAuthLoading(true);
    const user = await registerUser(authUsername, authPin, authRole);
    if (user) {
      setCurrentUser(user);
      await loadData();
      setAuthError('');
      setAuthUsername('');
      setAuthPin('');
    } else {
      setAuthError('Username already exists');
    }
    setAuthLoading(false);
  };

  const handleLogout = () => {
    logoutUser();
    setCurrentUser(null);
    setTasks([]);
    setUpdates([]);
    setSelectedTaskId(null);
    setActiveTab('overview');
    setFilterUser('ALL_TEAM');
  };

  const handleUpdateProfile = async () => {
    if (!currentUser) return;
    setProfileMessage(null);

    if (newPin.length < 4) {
      setProfileMessage({ type: 'error', text: 'PIN must be at least 4 digits.' });
      return;
    }
    if (newPin !== confirmPin) {
      setProfileMessage({ type: 'error', text: 'PINs do not match.' });
      return;
    }

    const updatedUser = { ...currentUser, pin: newPin };
    const success = await updateUser(updatedUser);

    if (success) {
      setCurrentUser(updatedUser);
      setProfileMessage({ type: 'success', text: 'PIN updated successfully!' });
      setNewPin('');
      setConfirmPin('');
    } else {
      setProfileMessage({ type: 'error', text: 'Failed to update profile.' });
    }
  };

  const handleToggleTeamMember = (userId: string) => {
    setSelectedTeamMemberIds(prev => 
      prev.includes(userId) ? prev.filter(id => id !== userId) : [...prev, userId]
    );
  };

  const handleAddSelectedMembers = async () => {
    if (!currentUser || currentUser.role !== 'ADMIN') return;
    if (selectedTeamMemberIds.length === 0) return;

    const success = await addTeamMembers(currentUser.id, selectedTeamMemberIds);
    if (success) {
      // Refresh current user data
      const updatedUser = await getCurrentUser();
      if (updatedUser) setCurrentUser(updatedUser);

      // Refresh all users list
      const u = await getUsers();
      setAllUsers(u);

      setSelectedTeamMemberIds([]);
      setShowTeamModal(false);
      alert(`${selectedTeamMemberIds.length} members added to your line!`);
    } else {
      alert('Failed to add members.');
    }
  };

  // --- Computed Data & Helpers ---

  const allCategories = useMemo(() => {
    const taskCategories = tasks.map(t => t.category);
    return Array.from(new Set([...CATEGORIES, ...taskCategories])).sort();
  }, [tasks]);

  const selectedTask = useMemo(() => 
    tasks.find(t => t.id === selectedTaskId), 
  [tasks, selectedTaskId]);

  const taskHistory = useMemo(() => {
    if (!selectedTaskId) return [];
    return updates
      .filter(u => u.taskId === selectedTaskId && !u.isArchived)
      .sort((a, b) => {
        return historySort === 'NEWEST' ? b.timestamp - a.timestamp : a.timestamp - b.timestamp;
      });
  }, [updates, selectedTaskId, historySort]);

  // User Map for fast lookup (id -> User Object)
  const userMap = useMemo(() => {
    return allUsers.reduce((acc, user) => {
      acc[user.id] = user;
      return acc;
    }, {} as Record<string, User>);
  }, [allUsers]);

  // Build Context for Chatbot
  const buildChatContext = () => {
    if (!currentUser) return '';

    // 1. Identify accessible tasks based on role
    const accessibleTasks = tasks.filter(t => {
        if (currentUser.role === 'ADMIN') {
             // Admins see their own + team members
             return t.userId === currentUser.id || currentUser.teamMemberIds.includes(t.userId);
        }
        return t.userId === currentUser.id;
    });

    // 2. Format Tasks
    const taskContext = accessibleTasks.length > 0 
      ? accessibleTasks.map(t => {
          const ownerName = userMap[t.userId]?.username || 'Unknown';
          return `- Task: "${t.title}" (Status: ${t.status}, Due: ${t.targetDate}, Category: ${t.category}, Owner: ${ownerName})`;
        }).join('\n')
      : "No tasks found.";

    // 3. Format Updates (associated with accessible tasks)
    const accessibleTaskIds = new Set(accessibleTasks.map(t => t.id));
    const relevantUpdates = updates
        .filter(u => accessibleTaskIds.has(u.taskId))
        .sort((a, b) => b.timestamp - a.timestamp) // Newest first
        .slice(0, 50); // Limit context to recent 50 updates to save tokens

    const updatesContext = relevantUpdates.length > 0
      ? relevantUpdates.map(u => {
          const task = tasks.find(t => t.id === u.taskId);
          return `- Update for "${task?.title || 'Unknown Task'}": "${u.content}" (Date: ${u.date})`;
        }).join('\n')
      : "No recent updates found.";

    return `
      You are the DailyPulse AI Assistant.
      You have access to the following real-time data from the DailyPulse app.

      STRICTLY use ONLY the provided TASKS and UPDATES data to answer the user's questions. 
      Do not hallucinate or invent information not present in the data below.
      If the answer is not in the data, politely state that you cannot find that information in the current records.

      CURRENT CONTEXT:
      User: ${currentUser.username} (${currentUser.role})
      Date: ${new Date().toISOString().split('T')[0]}

      TASKS DATA:
      ${taskContext}

      RECENT UPDATES DATA:
      ${updatesContext}
    `.trim();
  };

  // --- Chat Actions ---
  const handleSendChatMessage = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!chatInput.trim() || isChatLoading) return;

    const userMsg = chatInput;
    setChatInput('');
    setChatMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsChatLoading(true);

    // Prepare history for API
    const historyForSdk = chatMessages.map(msg => ({
      role: msg.role,
      parts: [{ text: msg.text }]
    }));

    // Build the system instruction with the latest data
    const systemInstruction = buildChatContext();

    const responseText = await chatWithAI(historyForSdk, userMsg, systemInstruction);

    setChatMessages(prev => [...prev, { role: 'model', text: responseText }]);
    setIsChatLoading(false);
  };

  // Team Members List (for Admin Filter)
  const teamMembers = useMemo(() => {
    if (!currentUser || currentUser.role !== 'ADMIN') return [];
    return currentUser.teamMemberIds
      .map(id => userMap[id])
      .filter(Boolean) as User[];
  }, [currentUser, userMap]); 

  // Available users to add (not me, not already in team)
  const availableUsersToAdd = useMemo(() => {
    if (!currentUser || currentUser.role !== 'ADMIN') return [];
    return allUsers.filter((u: User) => 
      u.id !== currentUser.id && 
      !currentUser.teamMemberIds.includes(u.id)
    );
  }, [currentUser, allUsers]);

  // --- Filtering & Sorting Logic ---
  const filteredTasks = useMemo(() => {
    if (!currentUser) return [];

    const now = new Date();
    now.setHours(0,0,0,0);

    // 1. Filter
    const filtered = tasks.filter(task => {
      // User Permission Filter
      let isVisible = false;
      if (currentUser.role === 'ADMIN') {
        if (filterUser === 'ME') {
          isVisible = task.userId === currentUser.id;
        } else if (filterUser === 'ALL_TEAM') {
          // Show Admin's tasks AND Team Members' tasks
          isVisible = task.userId === currentUser.id || currentUser.teamMemberIds.includes(task.userId);
        } else {
          // Specific user selected
          isVisible = task.userId === filterUser;
        }
      } else {
        // Regular Member sees only their own
        isVisible = task.userId === currentUser.id;
      }

      if (!isVisible) return false;

      // Standard Filters
      const matchesSearch = task.title.toLowerCase().includes(searchQuery.toLowerCase());

      // Single-select filters
      const matchesCategory = filterCategory === 'ALL' || task.category === filterCategory;
      const matchesStatus = filterStatus === 'ALL' || task.status === filterStatus;

      let matchesTime = true;
      const target = new Date(task.targetDate);
      target.setHours(0,0,0,0);
      const diffDays = (target.getTime() - now.getTime()) / (1000 * 3600 * 24);

      if (filterTime === 'OVERDUE') matchesTime = diffDays < 0;
      else if (filterTime === 'TODAY') matchesTime = diffDays === 0;
      else if (filterTime === 'THIS_WEEK') matchesTime = diffDays >= 0 && diffDays <= 7;
      else if (filterTime === 'FUTURE') matchesTime = diffDays > 7;

      return matchesSearch && matchesCategory && matchesStatus && matchesTime;
    });

    // 2. Sort
    return filtered.sort((a, b) => {
        switch (taskSort) {
            case 'DATE_ASC':
                return new Date(a.targetDate).getTime() - new Date(b.targetDate).getTime();
            case 'DATE_DESC':
                return new Date(b.targetDate).getTime() - new Date(a.targetDate).getTime();
            case 'STATUS_ASC':
                return STATUSES.indexOf(a.status) - STATUSES.indexOf(b.status);
            case 'STATUS_DESC':
                return STATUSES.indexOf(b.status) - STATUSES.indexOf(a.status);
            case 'CATEGORY_ASC':
                return a.category.localeCompare(b.category);
            case 'CATEGORY_DESC':
                return b.category.localeCompare(a.category);
            default:
                return 0;
        }
    });

  }, [tasks, searchQuery, filterCategory, filterStatus, filterTime, filterUser, currentUser, taskSort]);

  // --- Actions ---

  const handleTaskSelect = (id: string) => {
    setSelectedTaskId(id);
    setActiveTab('detail');
  };

  const handleSaveUpdate = async () => {
    if (!selectedTask || !updateContent.trim()) return;

    // Admin Check: If admin is updating another user's task
    if (currentUser?.role === 'ADMIN' && selectedTask.userId !== currentUser.id) {
      setShowAdminConfirmModal(true);
      return;
    }

    await executeSaveUpdate(false);
  };

  const handleConfirmAdminUpdate = async () => {
    setShowAdminConfirmModal(false);
    await executeSaveUpdate(true);
  };

  const executeSaveUpdate = async (isAdminOverride: boolean) => {
    if (!selectedTask || !updateContent.trim()) return;

    let finalContent = updateContent;
    if (isAdminOverride && currentUser) {
      finalContent = `${finalContent}\n(Updated by ${currentUser.username})`;
    }

    setIsSaving(true);

    // Check for status change
    let statusChangeData = undefined;
    if (lastStatus !== selectedTask.status) {
      statusChangeData = {
        from: lastStatus,
        to: selectedTask.status
      };

      // Update Task Status in DB
      const updatedTask = { ...selectedTask };
      setTasks(prev => prev.map(t => t.id === selectedTask.id ? updatedTask : t));
      await saveSingleTask(updatedTask);
    }

    if (editUpdateId) {
       const updatedUpdate = updates.find(u => u.id === editUpdateId);
       if (updatedUpdate) {
         const newUpdateObj = {
            ...updatedUpdate,
            content: finalContent,
            date: updateDate,
            statusChange: statusChangeData || updatedUpdate.statusChange
         };

         setUpdates(prev => prev.map(u => u.id === editUpdateId ? newUpdateObj : u));
         await saveSingleUpdate(newUpdateObj);
         setEditUpdateId(null);
       }
    } else {
      const newUpdate: TaskUpdate = {
        id: Date.now().toString(),
        taskId: selectedTask.id,
        date: updateDate,
        content: finalContent,
        timestamp: Date.now(),
        isArchived: false,
        statusChange: statusChangeData
      };
      setUpdates(prev => [newUpdate, ...prev]);
      await saveSingleUpdate(newUpdate);
    }

    if (statusChangeData) {
      setLastStatus(selectedTask.status);
    }

    setUpdateContent('');
    setUpdateDate(new Date().toISOString().split('T')[0]);
    setIsSaving(false);
  };

  const handleCancelEdit = () => {
    setEditUpdateId(null);
    setUpdateContent('');
    setUpdateDate(new Date().toISOString().split('T')[0]);
  };

  const handlePolish = async () => {
    if (!selectedTask || !updateContent.trim()) return;
    setIsPolishing(true);
    const polished = await polishUpdateText(updateContent, selectedTask.title, selectedTask.status);
    setUpdateContent(polished);
    setIsPolishing(false);
  };

  const handleTaskChange = async (field: keyof Task, value: any) => {
    if (!selectedTask) return;

    // Optimistic update
    const updatedTask = { ...selectedTask, [field]: value };
    setTasks(prev => prev.map(t => t.id === selectedTask.id ? updatedTask : t));

    // Save to DB (Debouncing would be better here in production, but simple save works)
    await saveSingleTask(updatedTask);
  };

  const handleAddToCalendar = (update: TaskUpdate) => {
    if (!selectedTask) return;
    const title = encodeURIComponent(`${selectedTask.title} - Update`);
    const details = encodeURIComponent(`Task: ${selectedTask.title}\nUpdate: ${update.content}`);
    const startDateStr = update.date.replace(/-/g, '');
    const dateObj = new Date(update.date);
    dateObj.setDate(dateObj.getDate() + 1);
    const endDateStr = dateObj.toISOString().split('T')[0].replace(/-/g, '');
    const dates = `${startDateStr}/${endDateStr}`;
    const url = `https://calendar.google.com/calendar/render?action=TEMPLATE&text=${title}&details=${details}&dates=${dates}`;
    window.open(url, '_blank');
  };

  const handleDeleteUpdate = async (update: TaskUpdate) => {
    setTimeout(async () => {
      if (window.confirm("Delete this update permanently?")) {
        setUpdates(prev => prev.filter(u => u.id !== update.id));
        await deleteUpdate(update.id);
        if (editUpdateId === update.id) {
          handleCancelEdit();
        }
      }
    }, 10);
  };

  const handleEditUpdateStart = (update: TaskUpdate) => {
    setUpdateContent(update.content);
    setUpdateDate(update.date);
    setEditUpdateId(update.id);
  };

  const createNewTask = async () => {
    if (!currentUser) return;
    const newTask: Task = {
      id: Date.now().toString(),
      userId: currentUser.id,
      title: 'New Task',
      category: CATEGORIES[0],
      status: TaskStatus.NOT_YET,
      targetDate: new Date().toISOString().split('T')[0],
      createdAt: Date.now()
    };

    setTasks([newTask, ...tasks]);
    setSelectedTaskId(newTask.id);
    setActiveTab('detail');
    setLastStatus(TaskStatus.NOT_YET);

    await saveSingleTask(newTask);
  };

  // Voice Recording
  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      let mimeType = 'audio/webm';
      if (!MediaRecorder.isTypeSupported(mimeType)) mimeType = 'audio/mp4';
      if (!MediaRecorder.isTypeSupported(mimeType)) mimeType = '';

      const recorder = mimeType ? new MediaRecorder(stream, { mimeType }) : new MediaRecorder(stream);
      const chunks: BlobPart[] = [];

      recorder.ondataavailable = (e) => { if (e.data.size > 0) chunks.push(e.data); };
      recorder.onstop = async () => {
        const blob = new Blob(chunks, { type: recorder.mimeType });
        stream.getTracks().forEach(track => track.stop());
        const reader = new FileReader();
        reader.onloadend = async () => {
          const base64Data = (reader.result as string).split(',')[1];
          await processVoiceData(base64Data, recorder.mimeType || 'audio/webm');
        };
        reader.readAsDataURL(blob);
      };
      recorder.start();
      mediaRecorderRef.current = recorder;
      setIsRecording(true);
    } catch (error) {
      console.error(error);
      alert("Microphone access denied.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setIsProcessingVoice(true);
    }
  };

  const processVoiceData = async (base64Data: string, mimeType: string) => {
    if (!currentUser) return;
    try {
      const result = await createTaskFromVoice(base64Data, mimeType);
      if (result) {
        const newTask: Task = {
          id: Date.now().toString(),
          userId: currentUser.id,
          title: result.title || 'New Voice Task',
          category: result.category || 'PERSONAL',
          status: (result.status as TaskStatus) || TaskStatus.NOT_YET,
          targetDate: result.targetDate || new Date().toISOString().split('T')[0],
          createdAt: Date.now()
        };
        setTasks(prev => [newTask, ...prev]);
        setSelectedTaskId(newTask.id);
        setActiveTab('detail');
        setLastStatus((result.status as TaskStatus) || TaskStatus.NOT_YET);

        await saveSingleTask(newTask);
      } else {
        alert("Could not understand voice command.");
      }
    } catch (error) {
      alert("Error processing voice command.");
    } finally {
      setIsProcessingVoice(false);
    }
  };

  const getDaysRemaining = (targetDate: string) => {
    const target = new Date(targetDate);
    const today = new Date();
    target.setHours(0,0,0,0);
    today.setHours(0,0,0,0);
    const diffTime = target.getTime() - today.getTime();
    return Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  };

  const getDaysLabel = (days: number) => {
    if (days < 0) return <span className="text-red-600 font-bold">{Math.abs(days)}d overdue</span>;
    if (days === 0) return <span className="text-amber-600 font-bold">Due Today</span>;
    return <span className="text-emerald-600">{days} days left</span>;
  };

  // --- RENDER ---

  // 1. AUTH SCREEN
  if (!currentUser) {
    return (
      <div className="flex h-screen w-full bg-beige items-center justify-center p-6">
        <div className="w-full max-w-md bg-white rounded-2xl shadow-xl overflow-hidden border border-stone-200">
           <div className="bg-primary p-8 text-center">
              <div className="w-16 h-16 bg-secondary text-primary rounded-2xl flex items-center justify-center text-2xl font-bold mx-auto mb-4 shadow-lg">DP</div>
              <h1 className="text-2xl font-bold text-secondary">DailyPulse</h1>
              <p className="text-secondary/80 font-medium">Team & Task Management</p>
           </div>

           <div className="p-8">
              <div className="flex bg-stone-100 p-1 rounded-xl mb-6">
