              </div>

              <div className="flex justify-between items-center mt-1 md:mt-0 md:contents">
                  <div className="md:col-span-2">
                    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-[10px] md:text-xs font-bold border ${STATUS_COLORS[task.status]}`}>
