                  <div className="text-xs md:text-sm text-stone-500 font-mono md:col-span-2 flex items-center gap-1">
                     <span className="md:hidden"><Calendar size={10}/></span> {formatListDate(task.targetDate)}
                  </div>
                  <div className="text-right text-xs font-bold md:col-span-2">
                    {getDaysLabel(getDaysRemaining(task.targetDate))}
