              </div>
            </div>
          ))}
          {filteredTasks.length === 0 && (
             <div className="flex flex-col items-center justify-center h-48 text-stone-400">
                <div className="w-12 h-12 bg-stone-100 rounded-full flex items-center justify-center mb-3">
                   <Filter size={20} className="opacity-50" />
                </div>
                <p>No matching tasks.</p>
             </div>
          )}
        </div>
      </div>

      {/* DETAIL / PROFILE / CHAT SECTION */}
      <div className={`
         flex-col md:flex-row bg-stone-50 border-t border-stone-200 shadow-[0_-4px_20px_rgba(0,0,0,0.05)] z-10
         absolute inset-0 bottom-16 top-0 md:relative md:bottom-auto md:top-auto md:h-[50vh] md:flex
         ${['detail', 'profile', 'chat'].includes(activeTab) ? 'flex animate-fade-in' : 'hidden md:flex'}
      `}>
        {activeTab === 'chat' ? (
          // --- CHAT VIEW ---
          <div className="w-full h-full flex flex-col bg-white animate-fade-in">
             <div className="p-4 border-b border-stone-200 flex items-center gap-2 bg-stone-50">
               <div className="w-8 h-8 bg-secondary rounded-full flex items-center justify-center text-primary">
                 <Bot size={18} />
