                 </div>
               ))}
               {isChatLoading && (
                 <div className="flex w-full justify-start">
                   <div className="bg-white px-4 py-3 rounded-2xl rounded-bl-none border border-stone-200 shadow-sm flex gap-1">
                     <span className="w-1.5 h-1.5 bg-stone-400 rounded-full animate-bounce"></span>
                     <span className="w-1.5 h-1.5 bg-stone-400 rounded-full animate-bounce delay-100"></span>
                     <span className="w-1.5 h-1.5 bg-stone-400 rounded-full animate-bounce delay-200"></span>
                   </div>
                 </div>
               )}
               <div ref={chatEndRef} />
             </div>

             <form onSubmit={handleSendChatMessage} className="p-4 bg-white border-t border-stone-200 shrink-0 flex gap-2">
               <input 
                 type="text" 
                 value={chatInput}
                 onChange={e => setChatInput(e.target.value)}
