export default App;

import { GoogleGenAI } from "@google/genai";
import { CATEGORIES, STATUSES } from '../constants';

const getAIClient = () => {
  if (!process.env.API_KEY) {
    console.warn("Gemini API Key is missing.");
    return null;
  }
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export const polishUpdateText = async (rawText: string, taskTitle: string, currentStatus: string): Promise<string> => {
  const ai = getAIClient();
  if (!ai) return rawText;

  try {
    const prompt = `
      You are a professional project manager assistant. 
      Rewrite the following status update note for the task "${taskTitle}" (Current Status: ${currentStatus}).
      Make it concise, professional, and clear. 
      Keep it under 3 sentences if possible.

      Raw Note: "${rawText}"
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    });

    return response.text?.trim() || rawText;
  } catch (error) {
    console.error("Error calling Gemini:", error);
    return rawText;
  }
};

export const chatWithAI = async (
  history: {role: string, parts: {text: string}[]}[],
  message: string,
  systemInstruction?: string
): Promise<string> => {
  const ai = getAIClient();
  if (!ai) return "AI Service Unavailable. Please check configuration.";

  try {
    const chat = ai.chats.create({
      model: 'gemini-2.5-flash',
      history: history,
      config: systemInstruction ? { systemInstruction } : undefined
    });

    const result = await chat.sendMessage({ message });
    return result.text || "I didn't get a response.";
  } catch (error) {
    console.error("Chat Error", error);
    return "I'm having trouble connecting right now. Please try again.";
  }
};

export const createTaskFromVoice = async (audioBase64: string, mimeType: string): Promise<{title: string, category: string, status: string, targetDate: string} | null> => {
  const ai = getAIClient();
  if (!ai) return null;

  // Use local date for prompt context
  const now = new Date();
  const year = now.getFullYear();
  const month = String(now.getMonth() + 1).padStart(2, '0');
  const day = String(now.getDate()).padStart(2, '0');
  const today = `${year}-${month}-${day}`;

  const categoriesList = CATEGORIES.join(', ');
  const statusesList = STATUSES.join(', ');

  const prompt = `
    You are a task management assistant.
    The user will provide a voice command to create a new task.
    The expected format usually contains: Category, Title, Target Date, and Status.

    Current Date: ${today}
    Allowed Categories: ${categoriesList} (Default to 'PERSONAL' if unclear).
    Allowed Statuses: ${statusesList} (Default to 'NOT_YET' if unclear).

    Extract the task details and return a JSON object with the following keys:
    - title (string)
    - category (string, must be one of the allowed)
    - targetDate (string, YYYY-MM-DD format. Convert relative dates like "next friday" to actual dates based on Current Date)
    - status (string, must be one of the allowed)

    If the user doesn't specify a field, infer it logically or use the default.
    Only return the JSON object.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
          { text: prompt },
          {
            inlineData: {
              mimeType: mimeType,
              data: audioBase64
            }
          }
        ]
      },
      config: {
        responseMimeType: "application/json"
      }
    });

    const text = response.text;
    if (!text) return null;
    return JSON.parse(text);
  } catch (error) {
    console.error("Error calling Gemini for voice task:", error);
    return null;
  }
};

