import { Task, TaskUpdate, TaskStatus, User, UserRole } from '../types';
import { supabase } from './supabaseClient';

const CURRENT_USER_KEY = 'dailypulse_current_user_id';

// --- AUTH SERVICE ---

export const getUsers = async (): Promise<User[]> => {
  const { data: users, error } = await supabase
    .from('users')
    .select('*');

  if (error || !users) return [];

  // For each user, fetch their team members
  const usersWithTeams = await Promise.all(users.map(async (u: any) => {
    const { data: teamData } = await supabase
      .from('team_memberships')
      .select('member_id')
      .eq('admin_id', u.id);

    return {
      id: u.id,
      username: u.username,
      pin: u.pin,
      role: u.role as UserRole,
      teamMemberIds: teamData ? teamData.map((t: any) => t.member_id) : []
    };
  }));

  return usersWithTeams;
};

export const registerUser = async (username: string, pin: string, role: UserRole): Promise<User | null> => {
  // Check if exists
  const { data: existing } = await supabase
    .from('users')
    .select('id')
    .ilike('username', username)
    .single();

  if (existing) return null;

  const newUser = {
    id: Date.now().toString(),
    username,
    pin,
    role
  };

  const { error } = await supabase.from('users').insert(newUser);

  if (error) {
    console.error("Register Error", error);
    return null;
  }

  return { ...newUser, teamMemberIds: [] };
};

export const loginUser = async (username: string, pin: string): Promise<User | null> => {
  const { data: user, error } = await supabase
    .from('users')
    .select('*')
    .ilike('username', username)
    .eq('pin', pin)
    .single();

  if (error || !user) return null;

  // Fetch team
  const { data: teamData } = await supabase
    .from('team_memberships')
    .select('member_id')
    .eq('admin_id', user.id);

  const fullUser: User = {
    id: user.id,
    username: user.username,
    pin: user.pin,
    role: user.role as UserRole,
    teamMemberIds: teamData ? teamData.map((t: any) => t.member_id) : []
  };

  localStorage.setItem(CURRENT_USER_KEY, fullUser.id);
  return fullUser;
};

export const getCurrentUser = async (): Promise<User | null> => {
  const id = localStorage.getItem(CURRENT_USER_KEY);
  if (!id) return null;

  const { data: user, error } = await supabase
    .from('users')
    .select('*')
    .eq('id', id)
    .single();

  if (error || !user) return null;

   // Fetch team
   const { data: teamData } = await supabase
   .from('team_memberships')
   .select('member_id')
   .eq('admin_id', user.id);

  return {
    id: user.id,
    username: user.username,
    pin: user.pin,
    role: user.role as UserRole,
    teamMemberIds: teamData ? teamData.map((t: any) => t.member_id) : []
  };
};

export const updateUser = async (updatedUser: User): Promise<boolean> => {
  const { error } = await supabase
    .from('users')
    .update({ pin: updatedUser.pin }) // Only pin update supported via UI currently
    .eq('id', updatedUser.id);

  return !error;
};

export const logoutUser = () => {
  localStorage.removeItem(CURRENT_USER_KEY);
};

export const addTeamMembers = async (adminId: string, memberIds: string[]): Promise<boolean> => {
  const inserts = memberIds.map(mid => ({
    admin_id: adminId,
    member_id: mid
  }));

  const { error } = await supabase.from('team_memberships').upsert(inserts, { onConflict: 'admin_id,member_id' });
  return !error;
};

// --- DATA SERVICE ---

export const getTasks = async (): Promise<Task[]> => {
  const { data, error } = await supabase.from('tasks').select('*');
  if (error || !data) return [];

  // Map snake_case DB to camelCase Types
  return data.map((t: any) => ({
    id: t.id,
    userId: t.user_id,
    title: t.title,
    category: t.category,
    status: t.status as TaskStatus,
    targetDate: t.target_date,
    createdAt: parseInt(t.created_at)
  }));
};

export const saveTasks = async (tasks: Task[]) => {
  // Upsert logic. 
  // IMPORTANT: This function previously saved ALL tasks. With Supabase, we should ideally only save CHANGED tasks.
  // However, based on the previous app logic, we'll iterate and upsert. 
  // For better performance in a real app, we would only call this on specific task changes.

  const dbTasks = tasks.map(t => ({
    id: t.id,
    user_id: t.userId,
    title: t.title,
    category: t.category,
    status: t.status,
    target_date: t.targetDate,
    created_at: t.createdAt
  }));

  const { error } = await supabase.from('tasks').upsert(dbTasks);
  if (error) console.error("Error saving tasks", error);
};

// Helper for single task save to avoid massive upserts
export const saveSingleTask = async (task: Task) => {
    const dbTask = {
        id: task.id,
        user_id: task.userId,
        title: task.title,
        category: task.category,
        status: task.status,
        target_date: task.targetDate,
        created_at: task.createdAt
    };
    await supabase.from('tasks').upsert(dbTask);
};

export const deleteTask = async (id: string) => {
    // Delete associated updates first
    await supabase.from('task_updates').delete().eq('task_id', id);
    // Delete the task
    await supabase.from('tasks').delete().eq('id', id);
};

export const getUpdates = async (): Promise<TaskUpdate[]> => {
  const { data, error } = await supabase.from('task_updates').select('*');
  if (error || !data) return [];

  return data.map((u: any) => ({
    id: u.id,
    taskId: u.task_id,
    date: u.date,
    content: u.content,
    timestamp: parseInt(u.timestamp),
    isArchived: u.is_archived,
    statusChange: (u.status_change_from && u.status_change_to) ? {
      from: u.status_change_from as TaskStatus,
      to: u.status_change_to as TaskStatus
    } : undefined
  }));
};

export const saveUpdates = async (updates: TaskUpdate[]) => {
  const dbUpdates = updates.map(u => ({
    id: u.id,
    task_id: u.taskId,
    date: u.date,
    content: u.content,
    timestamp: u.timestamp,
    is_archived: u.isArchived,
    status_change_from: u.statusChange?.from || null,
    status_change_to: u.statusChange?.to || null
  }));

  const { error } = await supabase.from('task_updates').upsert(dbUpdates);
  if (error) console.error("Error saving updates", error);
};

// Helper for single update save
export const saveSingleUpdate = async (u: TaskUpdate) => {
    const dbUpdate = {
        id: u.id,
        task_id: u.taskId,
        date: u.date,
